parameters.jsCode:
let result = {
  urgency_level: "Unknown",
  severity_score: 0,
  reasoning: "AI analysis failed or returned no data.",
  status: "analyzed"
};

try {
  const inputData = $input.first().json;

  if (inputData.error) {
    result.reasoning = "Error Log: " + (inputData.error.message || "API Error");
  } 

  const rawText = inputData?.candidates?.[0]?.content?.parts?.[0]?.text;

  if (rawText) {
    const cleanJson = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
    const parsed = JSON.parse(cleanJson);

    result.urgency_level = parsed.urgency_level || "Unknown";
    result.severity_score = parsed.severity_score || 0;
    result.reasoning = parsed.reasoning || "Analysis complete.";
  }
} catch (error) {
  result.reasoning = "Error processing output: " + error.message;
}

return result;
